"use strict";(self.webpackChunkpendle_documentation=self.webpackChunkpendle_documentation||[]).push([[3963],{9467:e=>{e.exports=JSON.parse('{"version":{"pluginId":"boros-dev","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"borosSidebar":[{"type":"link","label":"\ud83d\udcd6 Introduction","href":"/boros-dev/","docId":"Introduction","unlisted":false},{"type":"link","label":"\ud83d\udcc4 Lite Paper","href":"/boros-dev/LitePaper","docId":"LitePaper","unlisted":false},{"type":"link","label":"\ud83c\udfd7\ufe0f High Level Architecture","href":"/boros-dev/HighLevelArchitecture","docId":"HighLevelArchitecture","unlisted":false},{"type":"category","label":"\u2699\ufe0f Mechanics","items":[{"type":"link","label":"\ud83d\udcca Order Book","href":"/boros-dev/Mechanics/OrderBook","docId":"Mechanics/OrderBook","unlisted":false},{"type":"link","label":"\ud83d\udcb0 Margin","href":"/boros-dev/Mechanics/Margin","docId":"Mechanics/Margin","unlisted":false},{"type":"link","label":"\u2705 Settlement","href":"/boros-dev/Mechanics/Settlement","docId":"Mechanics/Settlement","unlisted":false},{"type":"link","label":"\ud83d\udcb5 Fees","href":"/boros-dev/Mechanics/Fees","docId":"Mechanics/Fees","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"\ud83d\udcdc Contracts","items":[{"type":"link","label":"\ud83d\udd00 Router","href":"/boros-dev/Contracts/Router","docId":"Contracts/Router","unlisted":false},{"type":"link","label":"\ud83c\udfea MarketHub","href":"/boros-dev/Contracts/MarketHub","docId":"Contracts/MarketHub","unlisted":false},{"type":"link","label":"\ud83d\udcc8 Market","href":"/boros-dev/Contracts/Market","docId":"Contracts/Market","unlisted":false},{"type":"link","label":"\ud83c\udfa8 Custom Types","href":"/boros-dev/Contracts/CustomTypes","docId":"Contracts/CustomTypes","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"\ud83d\udd0c Backend Integration","items":[{"type":"link","label":"\ud83d\udcd6 Overview","href":"/boros-dev/Backend/overview","docId":"Backend/overview","unlisted":false},{"type":"link","label":"\ud83d\udcda Glossary","href":"/boros-dev/Backend/glossary","docId":"Backend/glossary","unlisted":false},{"type":"link","label":"\ud83e\udd16 Agent","href":"/boros-dev/Backend/agent","docId":"Backend/agent","unlisted":false},{"type":"link","label":"\ud83c\udf10 API","href":"/boros-dev/Backend/api","docId":"Backend/api","unlisted":false},{"type":"link","label":"\ud83d\udce1 WebSocket","href":"/boros-dev/Backend/websocket","docId":"Backend/websocket","unlisted":false},{"type":"link","label":"\ud83c\udfaf Stop Orders","href":"/boros-dev/Backend/stop-orders","docId":"Backend/stop-orders","unlisted":false},{"type":"link","label":"\u2728 Best Practices","href":"/boros-dev/Backend/best-practices","docId":"Backend/best-practices","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"link","label":"\u2753 FAQ","href":"/boros-dev/FAQ","docId":"FAQ","unlisted":false}]},"docs":{"Backend/agent":{"id":"Backend/agent","title":"Agent Trading","description":"Overview","sidebar":"borosSidebar"},"Backend/api":{"id":"Backend/api","title":"Boros Open API","description":"This guide walks you through integrating with the Boros trading platform via the REST API. For exact request/response schemas and parameter details, see the interactive API docs.","sidebar":"borosSidebar"},"Backend/best-practices":{"id":"Backend/best-practices","title":"Boros API Best Practices","description":"This guide provides recommendations and common patterns for integrating with the Boros API efficiently.","sidebar":"borosSidebar"},"Backend/glossary":{"id":"Backend/glossary","title":"Glossary","description":"Quick reference for key terms used in the Boros API. For portfolio concepts (leverage, margin, PnL, liquidation), see the Boros User Glossary.","sidebar":"borosSidebar"},"Backend/overview":{"id":"Backend/overview","title":"Boros Public API Documentation","description":"Overview","sidebar":"borosSidebar"},"Backend/stop-orders":{"id":"Backend/stop-orders","title":"Stop Orders (TP/SL)","description":"Overview","sidebar":"borosSidebar"},"Backend/websocket":{"id":"Backend/websocket","title":"Boros WebSocket","description":"This guide explains how to directly connect to Boros\'s WebSocket service using Socket.IO client.","sidebar":"borosSidebar"},"Contracts/CustomTypes":{"id":"Contracts/CustomTypes","title":"Custom Types","description":"Boros heavily uses Solidity user-defined value types for gas optimization and type safety. These types use bit-packing to minimize storage costs and provide efficient operations on the EVM.","sidebar":"borosSidebar"},"Contracts/Market":{"id":"Contracts/Market","title":"Market View Functions","description":"The REST API provides all market data (positions, order books, margins) with up-to-date settlement applied. Direct contract calls return unsettled data and require manual settlement triggers. Use the API unless you have a specific need for on-chain reads.","sidebar":"borosSidebar"},"Contracts/MarketHub":{"id":"Contracts/MarketHub","title":"MarketHub View Functions","description":"The REST API exposes the same data (balances, withdrawals, entered markets) with proper settlement handling. Direct contract calls return unsettled data. Use the API unless you have a specific need for on-chain reads.","sidebar":"borosSidebar"},"Contracts/Router":{"id":"Contracts/Router","title":"Router Integration Guide","description":"Interacting with Boros contracts directly is not recommended for most use cases. The REST API and SDK handle authentication, calldata encoding, and transaction submission for you. Direct contract interaction is error-prone and may break if contract addresses or ABIs change. The information below is provided as a reference for advanced integrators only.","sidebar":"borosSidebar"},"FAQ":{"id":"FAQ","title":"Frequently Asked Questions","description":"Getting Started","sidebar":"borosSidebar"},"HighLevelArchitecture":{"id":"HighLevelArchitecture","title":"High Level Architecture","description":"For most integrations, interact with Boros through the REST API and SDK rather than calling contracts directly. The API handles calldata encoding, settlement, and transaction submission. The contract details below are provided as an architectural reference.","sidebar":"borosSidebar"},"Introduction":{"id":"Introduction","title":"Introduction to Boros","description":"Pendle Boros is an on-chain platform for trading interest rate swaps. The protocol enables users to take long or short positions on variable interest rates with leverage through a hybrid system combining a central limit order book and AMM. At launch, Boros only supports trading of funding rates, though Boros is designed to allow trading of any type of interest rate that has an index oracle.","sidebar":"borosSidebar"},"LitePaper":{"id":"LitePaper","title":"Boros Lite Paper","description":"This document outlines how Boros works in a more high level and user-centric manner. Exact formal definitions and formulas can be found in the whitepaper.","sidebar":"borosSidebar"},"Mechanics/Fees":{"id":"Mechanics/Fees","title":"Fees","description":"Boros charges various fees to maintain protocol sustainability. This section outlines all fee types that users should be aware of when trading on the platform.","sidebar":"borosSidebar"},"Mechanics/Margin":{"id":"Mechanics/Margin","title":"Margin","description":"Similar to other derivative exchanges, Boros supports both cross margin and isolated margin modes:","sidebar":"borosSidebar"},"Mechanics/OrderBook":{"id":"Mechanics/OrderBook","title":"Central Limit Order Book","description":"Boros implements a gas-optimized central limit order book (CLOB) specifically designed for the EVM. The order book architecture minimizes gas costs through lazy settlement and efficient data structures while maintaining the functionality expected from professional trading platforms.","sidebar":"borosSidebar"},"Mechanics/Settlement":{"id":"Mechanics/Settlement","title":"Settlement","description":"In Boros, settlement refers to the position update when a trade happens (e.g., market order placed, limit order filled) and the periodic floating payment.","sidebar":"borosSidebar"}}}}')}}]);